#include <stdio.h>
#include <stdbool.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    bool weekend[31] = {false};
    int wk[] = {6,13,20,27,7,14,21,28};
    for (int i = 0; i < 8; ++i) weekend[wk[i]] = true;
    while (T--) {
        int N; scanf("%d", &N);
        int extra = 0;
        for (int i = 0; i < N; ++i) {
            int d; scanf("%d", &d);
            if (!weekend[d]) ++extra;
        }
        printf("%d\n", 8 + extra);
    }
    return 0;
}

