#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    weekend = {6,13,20,27,7,14,21,28}
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        extra = 0
        for _ in range(N):
            d = int(next(it))
            if d not in weekend:
                extra += 1
        out_lines.append(str(8 + extra))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

